// Example: Fill and submit a web form in any web app
// Generated by ftl:rhdp-lab-validator for UI steps
//
// Environment variables:
//   APP_URL      — URL of the web application
//   FORM_FIELD_* — field name → value pairs (e.g. FORM_FIELD_name=myapp)
//   SUBMIT_TEXT  — button text to click (default: "Create" or "Submit")

const { chromium } = require('playwright');

(async () => {
  const appUrl     = process.env.APP_URL;
  const submitText = process.env.SUBMIT_TEXT || 'Create';

  if (!appUrl) {
    console.error('FAILED: APP_URL is required');
    process.exit(1);
  }

  // Collect form fields from env: FORM_FIELD_<name>=<value>
  const fields = {};
  for (const [key, val] of Object.entries(process.env)) {
    if (key.startsWith('FORM_FIELD_')) {
      fields[key.replace('FORM_FIELD_', '').toLowerCase()] = val;
    }
  }

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ ignoreHTTPSErrors: true });
  const page    = await context.newPage();

  try {
    await page.goto(appUrl);
    await page.waitForLoadState('networkidle');

    // Fill each field
    for (const [fieldName, fieldValue] of Object.entries(fields)) {
      const locator = page.locator(
        `[name="${fieldName}"], [placeholder*="${fieldName}"], label:has-text("${fieldName}") + * input`
      );
      await locator.first().fill(fieldValue);
    }

    // Submit
    await page.click(`button:has-text("${submitText}"), input[value="${submitText}"]`);
    await page.waitForLoadState('networkidle');

    console.log(`SUCCESS: Form submitted at ${appUrl}`);
    process.exit(0);
  } catch (err) {
    console.error(`FAILED: ${err.message}`);
    process.exit(1);
  } finally {
    await browser.close();
  }
})();
